######################################### Step 2: Influence Estimation #########################################
def compute_influence_factors(delta_kw=1.0):
    Loads = dss.Loads.AllNames()
    base_voltages = np.array(dss.Circuit.AllBusVMag())
    influences = []

    for load_name in Loads:
        dss.Loads.Name(load_name)
        base_kw = dss.Loads.kW()
        base_kvar = dss.Loads.kvar()

        # Apply small delta to kW
        dss.Loads.kW(base_kw + delta_kw)
        dss.Loads.kvar(base_kvar + 0.8 * delta_kw)
        dss.Solution.Solve()

        new_voltages = np.array(dss.Circuit.AllBusVMag())
        diff = np.sum(np.abs(new_voltages - base_voltages))
        influences.append(diff)

        # Reset
        dss.Loads.kW(base_kw)
        dss.Loads.kvar(base_kvar)

    dss.Solution.Solve()
    norm_influences = np.array(influences) / (np.max(influences) + 1e-9)
    return norm_influences

influence_factors = compute_influence_factors()

