######################################### Step 4: Greedy Heuristic #########################################
def greedy_load_adjustment_return_particles(adjustment_step=0.7, max_iter=5, tol=1e-3):
    Loads = dss.Loads.AllNames()
    num_loads = len(Loads)
    adjustments = [(0, 0) for _ in range(num_loads)]
    best_score = objective_function(adjustments)

    for iteration in range(max_iter):
        improved = False
        for i in range(num_loads):
            current_adj = adjustments[i]
            best_local_adj = current_adj
            best_local_score = best_score

            for delta in [-adjustment_step, 0.0, adjustment_step]:
                trial_adj = adjustments.copy()
                new_kw = current_adj[0] + delta
                new_kvar = 0.8 * new_kw
                trial_adj[i] = (new_kw, new_kvar)
                score = objective_function(trial_adj)

                if score < best_local_score:
                    best_local_score = score
                    best_local_adj = (new_kw, new_kvar)
                    improved = True

            adjustments[i] = best_local_adj
            best_score = best_local_score

        if not improved or best_score < tol:
            break

    flat_adjustments = [val for pair in adjustments for val in pair]
    return flat_adjustments

######################################### Step 5: PSO (Grid-aware) #########################################
def particle_swarm_optimization(num_particles=40, max_iter=300, w=0.7, c1=1.5, c2=1.5, initial_particles=None):
    Loads = dss.Loads.AllNames()
    num_dimensions = len(Loads) * 2
    particles = []

    if initial_particles:
        #particles.append(np.array(initial_particles))
        particles.append(np.array(initial_particles, dtype=float))
        while len(particles) < num_particles:
            #particles.append(np.random.uniform(-15, 15, size=num_dimensions))
            particles.append(np.random.uniform(-15, 15, size=num_dimensions).astype(float))
    else:
        #particles = [np.random.uniform(-15, 15, size=num_dimensions) for _ in range(num_particles)]
        particles = [np.random.uniform(-15, 15, size=num_dimensions).astype(float) for _ in range(num_particles)]
       # particles = [particles.append(np.random.uniform(-15, 15, size=num_dimensions).astype(float)) for _ in range(num_particles)]


    velocities = [np.zeros(num_dimensions) for _ in range(num_particles)]
    fitness = [objective_function(list(zip(p[::2], p[1::2]))) for p in particles]

    personal_best_positions = particles[:]
    personal_best_scores = fitness[:]
    global_best_index = np.argmin(fitness)
    global_best_position = particles[global_best_index]
    global_best_score = fitness[global_best_index]

    inf_vector = np.repeat(influence_factors, 2)  # for ΔkW and ΔkVAR

    for iter in range(max_iter):
        for i in range(num_particles):
            r1, r2 = np.random.rand(num_dimensions), np.random.rand(num_dimensions)
            velocities[i] = (w * velocities[i] +
                             c1 * r1 * (personal_best_positions[i] - particles[i]) +
                             c2 * r2 * (global_best_position - particles[i])) * inf_vector
            particles[i] += velocities[i]
            particles[i] = np.clip(particles[i], -100, 90)

            adj_pairs = list(zip(particles[i][::2], particles[i][1::2]))
            score = objective_function(adj_pairs)

            if score < personal_best_scores[i]:
                personal_best_positions[i] = particles[i].copy()
                personal_best_scores[i] = score

                if score < global_best_score:
                    global_best_position = particles[i].copy()
                    global_best_score = score

        if iter % 10 == 0 or iter == max_iter - 1:
            print(f"PSO Iteration {iter}: Best Score = {global_best_score:.6f}")

    final_adjustments = list(zip(global_best_position[::2], global_best_position[1::2]))
    return final_adjustments, global_best_score

######################################### Step 6: Local Search (Grid-aware) #########################################
def local_search(initial_adjustments, step_size=0.3, max_iter=50):
    current_adjustments = initial_adjustments.copy()
    current_score = objective_function(current_adjustments)

    for _ in range(max_iter):
        improved = False

        for i in range(len(current_adjustments)):
            for direction in [-1, 1]:
                temp_adjustments = current_adjustments.copy()
                perturbed_kw = temp_adjustments[i][0] + direction * step_size * influence_factors[i]
                temp_adjustments[i] = (perturbed_kw, 0.8 * perturbed_kw)

                score = objective_function(temp_adjustments)
                if score < current_score:
                    current_adjustments = temp_adjustments
                    current_score = score
                    improved = True
                    break

            if improved:
                break

        if not improved:
            break

    return current_adjustments, current_score

######################################### Step 7: Simulated Annealing (Grid-aware) #########################################
def simulated_annealing(initial_solution, initial_temp=100, final_temp=1, alpha=0.95, max_iter=50):
    current_solution = copy.deepcopy(initial_solution)
    current_score = objective_function(current_solution)
    best_solution = copy.deepcopy(current_solution)
    best_score = current_score
    temperature = initial_temp

    for iteration in range(max_iter):
        new_solution = []
        for i, (delta_kw, delta_kvar) in enumerate(current_solution):
            perturb = random.uniform(-0.5, 0.5) * influence_factors[i]
            new_kw = delta_kw + perturb
            new_kvar = 0.8 * new_kw
            new_solution.append((new_kw, new_kvar))

        new_score = objective_function(new_solution)
        delta_score = new_score - current_score

        if delta_score < 0 or random.uniform(0, 1) < math.exp(-delta_score / temperature):
            current_solution = new_solution
            current_score = new_score
            if current_score < best_score:
                best_solution = current_solution
                best_score = current_score

        temperature *= alpha
        if temperature < final_temp:
            break

    return best_solution, best_score

