# ================================
# Hybrid Optimization Demo
# Greedy → PSO → Local → SA
# ================================

import numpy as np
import matplotlib.pyplot as plt

np.random.seed(42)

# -------------------------------
# Problem definition
# -------------------------------
n_loads = 5
lb, ub = -5, 5

def objective(x):
    """Toy energy cost + nonconvex penalty"""
    cost = np.sum((x - 2)**2)
    penalty = 5 * np.sum(np.sin(x))
    return cost + penalty

# -------------------------------
# (1) Greedy Heuristic (3 iters)
# -------------------------------
def greedy_heuristic(x0, step=0.1, iters=5):
    x = x0.copy()
    history = []

    for _ in range(iters):
        for i in range(len(x)):
            candidates = [x[i] - step, x[i] + step]
            best_val = objective(x)

            for c in candidates:
                x_temp = x.copy()
                x_temp[i] = np.clip(c, lb, ub)
                val = objective(x_temp)

                if val < best_val:
                    x = x_temp
                    best_val = val

        history.append(best_val)

    return x, history

# -------------------------------
# (2) Particle Swarm Optimization (50 iters)
# -------------------------------
def pso(init, n_particles=20, iters=100):
    w, c1, c2 = 0.7, 1.5, 1.5

    particles = init + np.random.uniform(-1, 1, (n_particles, n_loads))
    velocities = np.zeros_like(particles)

    pbest = particles.copy()
    pbest_val = np.array([objective(p) for p in particles])

    gbest = pbest[np.argmin(pbest_val)]
    gbest_val = np.min(pbest_val)

    history = []

    for _ in range(iters):
        for i in range(n_particles):
            r1, r2 = np.random.rand(), np.random.rand()
            velocities[i] = (
                w * velocities[i]
                + c1 * r1 * (pbest[i] - particles[i])
                + c2 * r2 * (gbest - particles[i])
            )
            particles[i] += velocities[i]
            particles[i] = np.clip(particles[i], lb, ub)

            val = objective(particles[i])
            if val < pbest_val[i]:
                pbest[i] = particles[i]
                pbest_val[i] = val

        gbest = pbest[np.argmin(pbest_val)]
        gbest_val = np.min(pbest_val)
        history.append(gbest_val)

    return gbest, history

# -------------------------------
# (3) Local Search (10 iters)
# -------------------------------
def local_search(x0, step=0.05, iters=10):
    x = x0.copy()
    history = []

    for _ in range(iters):
        for i in range(len(x)):
            direction = np.sign(2 - x[i])
            x_new = x.copy()
            x_new[i] += direction * step
            x_new[i] = np.clip(x_new[i], lb, ub)

            if objective(x_new) < objective(x):
                x = x_new

        history.append(objective(x))

    return x, history

# -------------------------------
# (4) Simulated Annealing (10 iters)
# -------------------------------
def simulated_annealing(x0, T0=1.0, alpha=0.95, iters=10):
    x = x0.copy()
    best = x.copy()
    T = T0
    history = []

    for _ in range(iters):
        x_new = x + np.random.normal(0, 0.3, size=len(x))
        x_new = np.clip(x_new, lb, ub)

        delta = objective(x_new) - objective(x)
        if delta < 0 or np.random.rand() < np.exp(-delta / T):
            x = x_new

        if objective(x) < objective(best):
            best = x.copy()

        history.append(objective(best))
        T *= alpha

    return best, history

# -------------------------------
# Run full pipeline
# -------------------------------
x0 = np.random.uniform(lb, ub, n_loads)

x_greedy, hist_greedy = greedy_heuristic(x0)
x_pso, hist_pso = pso(x_greedy)
x_local, hist_local = local_search(x_pso)
x_sa, hist_sa = simulated_annealing(x_local)

# -------------------------------
# Plot convergence
# -------------------------------
plt.figure(figsize=(7,4))

plt.plot(hist_greedy, label="Greedy", linewidth=2)

plt.plot(
    range(len(hist_greedy), len(hist_greedy) + len(hist_pso)),
    hist_pso, label="PSO", linewidth=2
)

plt.plot(
    range(len(hist_greedy) + len(hist_pso),
          len(hist_greedy) + len(hist_pso) + len(hist_local)),
    hist_local, label="Local Search", linewidth=1.5
)

plt.plot(
    range(len(hist_greedy) + len(hist_pso) + len(hist_local),
          len(hist_greedy) + len(hist_pso) + len(hist_local) + len(hist_sa)),
    hist_sa, label="Simulated Annealing", linewidth=1.5
)

# Stage separators
plt.axvline(len(hist_greedy), linestyle="--", linewidth=1)
plt.axvline(len(hist_greedy) + len(hist_pso), linestyle="--", linewidth=1)
plt.axvline(len(hist_greedy) + len(hist_pso) + len(hist_local), linestyle="--", linewidth=1)

plt.xlabel("Iteration")
plt.ylabel("Objective Value")
plt.title("Hybrid Optimization Process (Greedy → PSO → Local → SA)")
plt.legend()
plt.grid(True)
plt.show()

# -------------------------------
# Run 10 problems
# -------------------------------
N_PROBLEMS = 10
all_histories = []

for k in range(N_PROBLEMS):
    x0 = np.random.uniform(lb, ub, n_loads)

    x_greedy, hist_greedy = greedy_heuristic(x0)
    x_pso, hist_pso = pso(x_greedy)
    x_local, hist_local = local_search(x_pso)
    x_sa, hist_sa = simulated_annealing(x_local)

    full_history = (
        hist_greedy
        + hist_pso
        + hist_local
        + hist_sa
    )

    all_histories.append(full_history)

# -------------------------------
# Plot all 10 runs in ONE figure
# -------------------------------
plt.figure(figsize=(6,3))

for i, hist in enumerate(all_histories):
    plt.plot(hist, alpha=0.7, label=f"Prob {i+1}")

# Stage boundaries
g_len = len(hist_greedy)
p_len = len(hist_pso)
l_len = len(hist_local)

plt.axvline(g_len, linestyle="--", linewidth=1)
plt.axvline(g_len + p_len, linestyle="--", linewidth=1)
plt.axvline(g_len + p_len + l_len, linestyle="--", linewidth=1)

plt.text(g_len/2, all_histories[0][0], "Greedy", ha="center")
plt.text(g_len + p_len/2, all_histories[0][0], "PSO", ha="center")
plt.text(g_len + p_len + l_len/2, all_histories[0][0], "LS", ha="center")
plt.text(len(all_histories[0]) - 10, all_histories[0][0], "SA", ha="center")

plt.xlabel("Iteration")
plt.ylabel("Objective Value")
plt.title("Hybrid Optimization Convergence for 10 Problem Instances")
plt.grid(True)

# Optional: comment this out if legend is too busy
plt.legend(ncol=2, fontsize=8)

plt.show()

"""**Figures for the Journal Paper**"""

# Convert to array (runs × iterations)
all_histories_array = np.array(all_histories)

mean_curve = np.mean(all_histories_array, axis=0)
