"""**Plotting of the process of "Integrated Framework: LP+Hybrid Optimization Algorithm"**"""

import numpy as np
import matplotlib.pyplot as plt
from mpl_toolkits.mplot3d import Axes3D

# -------------------------------
# Parameters
# -------------------------------
N_PROBLEMS = 10
P = 20  # PSO particles
T = 30  # PSO iterations
n_vars = 2  # 2D problems for 3D plot

# -------------------------------
# Benchmark functions (2D)
# -------------------------------
def Ackley(x):
    a = 20; b = 0.2; c = 2*np.pi
    return -a*np.exp(-b*np.sqrt(0.5*(x[0]**2+x[1]**2))) - np.exp(0.5*(np.cos(c*x[0])+np.cos(c*x[1]))) + a + np.exp(1)

def Rastrigin(x):
    return 20 + x[0]**2 - 10*np.cos(2*np.pi*x[0]) + x[1]**2 - 10*np.cos(2*np.pi*x[1])

def Eggholder(x):
    return -(x[1]+47)*np.sin(np.sqrt(abs(x[1]+x[0]/2+47))) - x[0]*np.sin(np.sqrt(abs(x[0]-(x[1]+47))))

def Holder_table(x):
    return -abs(np.sin(x[0])*np.cos(x[1])*np.exp(abs(1-(np.sqrt(x[0]**2+x[1]**2)/np.pi))))

def Levy(x):
    w1 = 1 + (x[0]-1)/4
    w2 = 1 + (x[1]-1)/4
    return (np.sin(np.pi*w1))**2 + ((w1-1)**2)*(1+10*(np.sin(np.pi*w1+1)**2)) + ((w2-1)**2)*(1+np.sin(2*np.pi*w2)**2)

def Schaffer2(x):
    return 0.5 + (np.sin(x[0]**2 - x[1]**2)**2 - 0.5)/(1+0.001*(x[0]**2 + x[1]**2))**2

def Shubert(x):
    return (np.sum([i*np.cos((i+1)*x[0]+i) for i in range(1,6)])) * (np.sum([i*np.cos((i+1)*x[1]+i) for i in range(1,6)]))

def Griewank(x):
    return (x[0]**2 + x[1]**2)/4000 - np.cos(x[0])*np.cos(x[1]/np.sqrt(2)) + 1

def Cross_in_tray(x):
    return -0.0001*(abs(np.sin(x[0])*np.sin(x[1])*np.exp(abs(100 - np.sqrt(x[0]**2+x[1]**2)/np.pi)))+1)**0.1

def Drop_wave(x):
    r = np.sqrt(x[0]**2 + x[1]**2)
    return -(1+np.cos(12*r))/(1+0.5*r**2)

benchmarks = [Ackley, Rastrigin, Eggholder, Holder_table, Levy,
              Schaffer2, Shubert, Griewank, Cross_in_tray, Drop_wave]

# -------------------------------
# LP: simple linear step toward min (demo)
# -------------------------------
def linear_programming(x0, obj):
    grad = np.random.uniform(-0.5,0.5,size=n_vars)  # demo linearization
    x_lp = x0 - 0.1*grad
    return x_lp, [obj(x_lp)]

# -------------------------------
# Greedy heuristic
# -------------------------------
def greedy_heuristic(x0, obj):
    x = x0.copy()
    history = []
    for _ in range(5):
        x += np.random.uniform(-0.05,0.05,size=n_vars)
        history.append(obj(x))
    return x, history

# -------------------------------
# PSO with trajectory
# -------------------------------
def pso(x0, obj, P=20, T=30):
    particles = np.random.uniform(0,1,(P,n_vars))
    vel = np.zeros_like(particles)
    pbest = particles.copy()
    pbest_val = np.array([obj(p) for p in particles])
    gbest = pbest[np.argmin(pbest_val)]
    history = []
    traj = np.zeros((T, P, n_vars))

    for t in range(T):
        for i in range(P):
            vel[i] = 0.5*vel[i] + 0.5*np.random.rand()*(pbest[i]-particles[i]) + 0.5*np.random.rand()*(gbest-particles[i])
            particles[i] += vel[i]
            val = obj(particles[i])
            if val < pbest_val[i]:
                pbest[i] = particles[i].copy()
                pbest_val[i] = val
        gbest = pbest[np.argmin(pbest_val)]
        history.append(obj(gbest))
        traj[t,:,:] = particles
    return gbest, history, traj

# -------------------------------
# Local search
# -------------------------------
def local_search(x0, obj):
    x = x0.copy()
    history = []
    for _ in range(5):
        x += np.random.uniform(-0.02,0.02,size=n_vars)
        history.append(obj(x))
    return x, history

# -------------------------------
# Simulated annealing
# -------------------------------
def simulated_annealing(x0, obj):
    x = x0.copy()
    history = []
    T0 = 1.0
    for _ in range(5):
        new_x = x + np.random.uniform(-0.05,0.05,size=n_vars)
        dE = obj(new_x)-obj(x)
        if dE<0 or np.random.rand()<np.exp(-dE/T0):
            x = new_x
        history.append(obj(x))
        T0 *= 0.9
    return x, history

# -------------------------------
# Run 10 benchmark problems
# -------------------------------
all_histories = []
all_particles = []

for k in range(N_PROBLEMS):
    x0 = np.random.rand(n_vars)
    obj = benchmarks[k]

    # LP
    x_lp, hist_lp = linear_programming(x0, obj)

    # Greedy
    x_g, hist_g = greedy_heuristic(x_lp, obj)

    # PSO
    x_p, hist_p, particles = pso(x_g, obj, P=P, T=T)

    # LS
    x_l, hist_l = local_search(x_p, obj)

    # SA
    x_sa, hist_sa = simulated_annealing(x_l, obj)

    full_history = hist_lp + hist_g + hist_p + hist_l + hist_sa
    all_histories.append(full_history)
    all_particles.append(particles)

# -------------------------------
# Plot 3D surface + PSO for each benchmark
# -------------------------------
for k in range(N_PROBLEMS):
    obj = benchmarks[k]

    x = np.linspace(0,1,50)
    y = np.linspace(0,1,50)
    X,Y = np.meshgrid(x,y)
    Z = np.array([[obj([xi,yi]) for xi,yi in zip(X[j],Y[j])] for j in range(X.shape[0])])

    fig = plt.figure(figsize=(6,5))
    ax = fig.add_subplot(111, projection='3d')

    # Choose visualization style
    style = 'contour'  # options: 'surface', 'wireframe', 'contour', 'scatter', 'hybrid'

    if style=='surface':
        ax.plot_surface(X,Y,Z, alpha=0.7, cmap='viridis', edgecolor='none')
    elif style=='wireframe':
        ax.plot_wireframe(X,Y,Z, rstride=2, cstride=2, color='gray', linewidth=0.8)
    elif style=='contour':
        ax.contour3D(X,Y,Z, 50, cmap='coolwarm', linestyles='solid', offset=np.min(Z)-0.5)
        ax.plot_surface(X,Y,Z, alpha=0.3, cmap='viridis')
    elif style=='scatter':
        ax.scatter(X.flatten(), Y.flatten(), Z.flatten(), c=Z.flatten(), cmap='plasma', marker='o', alpha=0.6)
    elif style=='hybrid':
        ax.plot_surface(X,Y,Z, alpha=0.5, cmap='viridis')
        ax.plot_wireframe(X,Y,Z, rstride=5, cstride=5, color='black', linewidth=0.5)

    # Overlay PSO trajectories
    traj = all_particles[k]
    for i in range(P):
        ax.plot(traj[:,i,0], traj[:,i,1], [obj(pos) for pos in traj[:,i,:]], '*', color='m', alpha=0.4)

    ax.set_xlabel("x1")
    ax.set_ylabel("x2")
    ax.set_zlabel("Objective")
    ax.set_title(f"{obj.__name__}")#"Benchmark {k+1}: {obj.__name__}"
    plt.show()

import numpy as np
import matplotlib.pyplot as plt
from mpl_toolkits.mplot3d import Axes3D

# -------------------------------
# Parameters
# -------------------------------
N_PROBLEMS = 12
P = 20  # PSO particles
T = 30  # PSO iterations
n_vars = 2  # 2D problems for 3D plot

# 1️⃣ Ackley
def ackley(x):
    a, b, c = 20, 0.2, 2*np.pi
    x1, x2 = x[0], x[1]
    return -a*np.exp(-b*np.sqrt(0.5*(x1**2 + x2**2))) \
           - np.exp(0.5*(np.cos(c*x1) + np.cos(c*x2))) \
           + a + np.exp(1)

# 2️⃣ Rastrigin
def rastrigin(x):
    x1, x2 = x[0], x[1]
    return 20 + x1**2 - 10*np.cos(2*np.pi*x1) \
               + x2**2 - 10*np.cos(2*np.pi*x2)

# 3️⃣ Eggholder
def eggholder(x):
    x1, x2 = x[0], x[1]
    return -(x2 + 47)*np.sin(np.sqrt(abs(x2 + x1/2 + 47))) \
           - x1*np.sin(np.sqrt(abs(x1 - (x2 + 47))))

# 4️⃣ Holder Table
def holder_table(x):
    x1, x2 = x[0], x[1]
    return -abs(np.sin(x1)*np.cos(x2) *
                np.exp(abs(1 - np.sqrt(x1**2 + x2**2)/np.pi)))

# 5️⃣ Levy
def levy(x):
    x1, x2 = x[0], x[1]
    w1 = 1 + (x1 - 1)/4
    w2 = 1 + (x2 - 1)/4
    return (np.sin(np.pi*w1))**2 \
           + (w1 - 1)**2 * (1 + 10*(np.sin(np.pi*w1 + 1))**2) \
           + (w2 - 1)**2 * (1 + (np.sin(2*np.pi*w2))**2)

# 6️⃣ Schaffer N.2
def schaffer2(x):
    x1, x2 = x[0], x[1]
    return 0.5 + (np.sin(x1**2 - x2**2)**2 - 0.5) / \
           (1 + 0.001*(x1**2 + x2**2))**2

# 7️⃣ Shubert
def shubert(x):
    x1, x2 = x[0], x[1]
    sum1 = np.sum([i*np.cos((i+1)*x1 + i) for i in range(1,6)])
    sum2 = np.sum([i*np.cos((i+1)*x2 + i) for i in range(1,6)])
    return sum1 * sum2

# 8️⃣ Griewank
def griewank(x):
    x1, x2 = x[0], x[1]
    return (x1**2 + x2**2)/4000 \
           - np.cos(x1)*np.cos(x2/np.sqrt(2)) + 1

# 9️⃣ Cross-in-Tray
def cross_in_tray(x):
    x1, x2 = x[0], x[1]
    return -0.0001 * (
        abs(np.sin(x1)*np.sin(x2) *
            np.exp(abs(100 - np.sqrt(x1**2 + x2**2)/np.pi))) + 1
    )**0.1

# 🔟 Drop-Wave
def drop_wave(x):
    x1, x2 = x[0], x[1]
    r = np.sqrt(x1**2 + x2**2)
    return -(1 + np.cos(12*r)) / (1 + 0.5*r**2)

# 1️⃣1️⃣ Bukin Function N.6
def bukin_n6(x):
    x1, x2 = x[0], x[1]
    return 100*np.sqrt(abs(x2 - 0.01*x1**2)) \
           + 0.01*abs(x1 + 10)

# 1️⃣2️⃣ Langermann
def langermann(x):
    x1, x2 = x[0], x[1]

    # Standard parameters (m=5)
    A = np.array([[3,5,2,1,7],
                  [5,2,1,4,9]])
    c = np.array([1,2,5,2,3])

    m = 5
    total = 0
    for i in range(m):
        term = (x1 - A[0,i])**2 + (x2 - A[1,i])**2
        total += c[i] * np.exp(-term/np.pi) * np.cos(np.pi*term)

    return total

